1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive with 2 neighbors (survival)", () => {
15	    // Horizontal line of 3 cells: the middle cell (1,0) has 2 neighbors and survives.
16	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
17	    expect(result).toContainEqual([1, 0]);
18	  });
19	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
20	    // (1,1) has 4 live neighbors: (0,0), (1,0), (0,1), (2,1) -> dies
21	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1], [2, 1]]);
22	    expect(result).not.toContainEqual([1, 1]);
23	  });
24	  it("should bring a dead cell to life with exactly 3 neighbors (reproduction)", () => {
25	    // Dead cell (1,1) has 3 live neighbors: (0,0), (1,0), (0,1) -> becomes alive
