export function nextGeneration(liveCells: LiveCell[]): LiveCell[] {
  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
  const neighborCounts = new Map<string, number>();
  const candidateCells = new Map<string, LiveCell>();

  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: LiveCell = [x + dx, y + dy];
      const key = cellKey(neighbor[0], neighbor[1]);
      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
      candidateCells.set(key, neighbor);
    }
  }

  const survivesOrBorn = (key: string, count: number): boolean =>
    liveSet.has(key) ? count === 2 || count === 3 : count === 3;

  return [...neighborCounts.entries()]
    .filter(([key, count]) => survivesOrBorn(key, count))
    .map(([key]) => candidateCells.get(key)!);
}
